LAYER
  NAME "cambios_temperatura_minima_setiembre_octubre_noviembre_periodo_2030"
  GROUP "Escenarios Climáticos"
  STATUS off
  DATA "archivos/raster/cambios_temperatura_minima_setiembre_octubre_noviembre_periodo_2030.img"
  TYPE RASTER
  TRANSPARENCY 100
  DUMP true
  HEADER   "plantillas/inicio.html"
  TEMPLATE "plantillas/raster.html"
  FOOTER   "plantillas/fin.html" 
  PROJECTION
	"init=epsg:32718"
  END
  METADATA
	"wms_encoding" "LATIN1"
	"layer_encoding" "LATIN1"
	"wms_group_title" "Escenarios Climáticos"
	"queryable" "true"
	"wms_metadataurl_type" "TC211"
	"wms_title" "Cambios de temperatura mínima set,oct,nov (Ańo 2030)"
	"wms_abstract" "Cambios de temperatura mínima setiembre,octubre,noviembre periodo 2030, con referencia al periodo base 1971-2000 - Copyright © Servicio Nacional de Meteorología e Hidrología - SENAMHI, fecha: Junio 2010 :: http://www.senamhi.gob.pe, Publicado por el  para el Programa de Adaptación al Cambio Climático  - PACC Perú 2013 :: http://www.paccperu.org.pe"
	"wms_dataurl_href" "../descargar/cambios_temperatura_minima_setiembre_octubre_noviembre_periodo_2030.rar" 
	"autor" "© SENAMHI (Junio 2010) - PACC Perú"
	"wms_extent" "609253.687525827 8286928 1004503.68752583 8759678"
	"wms_srs" "EPSG:32718"
	"wms_include_items" "all"
	"wms_exclude_items" "value_0,red,green,blue"
	"force_imagetype" "jpeg"
  END
  CLASS
	NAME "Cambios de temperatura mínima (°C)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "0.6 - 0.8"
    EXPRESSION ([pixel] >= 0.6 AND [pixel] < 0.8)
    COLOR 255 167 156
  END
  CLASS
	NAME "0.8 - 1.0"
    EXPRESSION ([pixel] >= 0.8 AND [pixel] < 1.0)
    COLOR 252 132 111
  END
  CLASS
	NAME "1.0 - 1.2"
    EXPRESSION ([pixel] >= 1.0 AND [pixel] < 1.2)
    COLOR 245 97 71
  END
  CLASS
	NAME "1.2 - 1.4"
    EXPRESSION ([pixel] >= 1.2 AND [pixel] <= 1.5)
    COLOR 232 60 37
  END

END # Layer